sys_ui_page.client_script:
// dialog_button id="cancel" was clicked, user does not want to delete the task
function cancelDeleteTask() {
    // below will auto close popup
    GlideDialogWindow.get().destroy();
    return false;
}

// dialog_button id="delete" was clicked, user confirms wanting to delete the task
function deleteTask() {
    return true;
}

sys_ui_page.processing_script:
deleteTask();

function deleteTask() {
    var gr = new GlideRecord("x_153465_discovert_route_task_instance");
    gr.addQuery('sys_id', sysid);
    gr.query();
    if (gr.next()) {
        // Calls a Server function
        new Task_uiAction().uiAction_DeleteTasks(gr);

    }
    // response.sendRedirect("/x_153465_discovert_route_task_instance.do?sysparm_view=default&sys_id=" + sysid);
	response.sendRedirect('/discovertaskerportal');
}
